import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"人民英雄纪念碑","description":"","frontmatter":{},"headers":[],"relativePath":"history/monument.md","filePath":"history/monument.md","lastUpdated":null}'),n={name:"history/monument.md"};function d(o,t,s,i,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="人民英雄纪念碑" tabindex="-1">人民英雄纪念碑 <a class="header-anchor" href="#人民英雄纪念碑" aria-label="Permalink to &quot;人民英雄纪念碑&quot;">​</a></h1><blockquote><p>&quot;人民英雄永垂不朽！&quot; —— 毛泽东</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>人民英雄纪念碑位于天安门广场中央，是中华人民共和国政府为纪念中国近现代史上的革命烈士而建造的纪念性建筑。碑高37.94米，碑身正面镌刻着毛泽东题写的&quot;人民英雄永垂不朽&quot;八个大字。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">全天开放</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">30分钟</td></tr><tr><td style="text-align:left;"><strong>最佳时间</strong></td><td style="text-align:left;">全天</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线天安门东/西站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区天安门广场中央</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="提议修建" tabindex="-1">提议修建 <a class="header-anchor" href="#提议修建" aria-label="Permalink to &quot;提议修建&quot;">​</a></h3><p>1949年9月30日，中国人民政治协商会议第一届全体会议决定，在首都北京建立人民英雄纪念碑，纪念在人民解放战争和人民革命中牺牲的人民英雄。</p><h3 id="奠基" tabindex="-1">奠基 <a class="header-anchor" href="#奠基" aria-label="Permalink to &quot;奠基&quot;">​</a></h3><p>1949年9月30日下午，毛泽东主席率领全体政协委员在天安门广场举行奠基典礼，毛泽东亲自执锨铲土，为纪念碑奠基。</p><h3 id="设计建造" tabindex="-1">设计建造 <a class="header-anchor" href="#设计建造" aria-label="Permalink to &quot;设计建造&quot;">​</a></h3><p>纪念碑的设计方案经过全国征集，最终由著名建筑师梁思成、林徽因等人主持设计。1952年8月正式动工，1958年4月竣工，历时近6年。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="碑身" tabindex="-1">碑身 <a class="header-anchor" href="#碑身" aria-label="Permalink to &quot;碑身&quot;">​</a></h3><p>人民英雄纪念碑由碑身、碑座、台基三部分组成。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>总高度</strong></td><td style="text-align:left;">37.94米</td></tr><tr><td style="text-align:left;"><strong>碑身高</strong></td><td style="text-align:left;">14.7米</td></tr><tr><td style="text-align:left;"><strong>碑座高</strong></td><td style="text-align:left;">13米</td></tr><tr><td style="text-align:left;"><strong>台基高</strong></td><td style="text-align:left;">10.24米</td></tr><tr><td style="text-align:left;"><strong>碑身尺寸</strong></td><td style="text-align:left;">长14.7米，宽2.9米，厚1米</td></tr><tr><td style="text-align:left;"><strong>重量</strong></td><td style="text-align:left;">约1万吨</td></tr></tbody></table><h3 id="碑身正面" tabindex="-1">碑身正面 <a class="header-anchor" href="#碑身正面" aria-label="Permalink to &quot;碑身正面&quot;">​</a></h3><p>碑身正面（北面）镌刻着毛泽东题写的&quot;人民英雄永垂不朽&quot;八个鎏金大字。每个字高2米，宽1.5米，笔力雄健，气势磅礴。</p><h3 id="碑身背面" tabindex="-1">碑身背面 <a class="header-anchor" href="#碑身背面" aria-label="Permalink to &quot;碑身背面&quot;">​</a></h3><p>碑身背面（南面）是毛泽东撰文、周恩来书写的碑文。碑文共150字，字体为楷书，庄严肃穆。</p><h4 id="碑文全文" tabindex="-1">碑文全文 <a class="header-anchor" href="#碑文全文" aria-label="Permalink to &quot;碑文全文&quot;">​</a></h4><blockquote><p>&quot;三年以来，在人民解放战争和人民革命中牺牲的人民英雄们永垂不朽！</p><p>三十年以来，在人民解放战争和人民革命中牺牲的人民英雄们永垂不朽！</p><p>由此上溯到一千八百四十年，从那时起，为了反对内外敌人，争取民族独立和人民自由幸福，在历次斗争中牺牲的人民英雄们永垂不朽！&quot;</p></blockquote><h3 id="浮雕" tabindex="-1">浮雕 <a class="header-anchor" href="#浮雕" aria-label="Permalink to &quot;浮雕&quot;">​</a></h3><p>纪念碑下层须弥座束腰部镶嵌着十幅汉白玉浮雕，每幅高2米，总长约40米，生动地再现了中国人民一百多年来的革命斗争历程。</p><table tabindex="0"><thead><tr><th style="text-align:left;">浮雕</th><th style="text-align:left;">内容</th><th style="text-align:center;">时间</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>销毁鸦片烟</strong></td><td style="text-align:left;">虎门销烟</td><td style="text-align:center;">1839年</td></tr><tr><td style="text-align:left;"><strong>金田起义</strong></td><td style="text-align:left;">太平天国运动</td><td style="text-align:center;">1851年</td></tr><tr><td style="text-align:left;"><strong>武昌起义</strong></td><td style="text-align:left;">辛亥革命</td><td style="text-align:center;">1911年</td></tr><tr><td style="text-align:left;"><strong>五四运动</strong></td><td style="text-align:left;">反帝反封建运动</td><td style="text-align:center;">1919年</td></tr><tr><td style="text-align:left;"><strong>五卅运动</strong></td><td style="text-align:left;">反帝爱国运动</td><td style="text-align:center;">1925年</td></tr><tr><td style="text-align:left;"><strong>南昌起义</strong></td><td style="text-align:left;">中国共产党武装起义</td><td style="text-align:center;">1927年</td></tr><tr><td style="text-align:left;"><strong>抗日游击战</strong></td><td style="text-align:left;">敌后抗日斗争</td><td style="text-align:center;">1937-1945年</td></tr><tr><td style="text-align:left;"><strong>胜利渡长江</strong></td><td style="text-align:left;">解放战争</td><td style="text-align:center;">1949年</td></tr><tr><td style="text-align:left;"><strong>支援前线</strong></td><td style="text-align:left;">人民支援解放战争</td><td style="text-align:center;">1946-1949年</td></tr><tr><td style="text-align:left;"><strong>欢迎解放军</strong></td><td style="text-align:left;">人民欢迎人民解放军</td><td style="text-align:center;">1949年</td></tr></tbody></table><h3 id="碑座装饰" tabindex="-1">碑座装饰 <a class="header-anchor" href="#碑座装饰" aria-label="Permalink to &quot;碑座装饰&quot;">​</a></h3><p>碑座上下两层须弥座，上层小，下层大。座上刻有荷花、菊花、牡丹等花卉图案，以及云纹、龙纹等装饰。</p><h3 id="建筑材料" tabindex="-1">建筑材料 <a class="header-anchor" href="#建筑材料" aria-label="Permalink to &quot;建筑材料&quot;">​</a></h3><p>纪念碑采用青岛浮山花岗岩建造，这种花岗岩质地坚硬，色泽美观，耐腐蚀。</p><h2 id="设计团队" tabindex="-1">设计团队 <a class="header-anchor" href="#设计团队" aria-label="Permalink to &quot;设计团队&quot;">​</a></h2><h3 id="建筑师" tabindex="-1">建筑师 <a class="header-anchor" href="#建筑师" aria-label="Permalink to &quot;建筑师&quot;">​</a></h3><ul><li><strong>梁思成</strong>：著名建筑学家，主持总体设计</li><li><strong>林徽因</strong>：著名建筑师、诗人，参与设计</li></ul><h3 id="浮雕作者" tabindex="-1">浮雕作者 <a class="header-anchor" href="#浮雕作者" aria-label="Permalink to &quot;浮雕作者&quot;">​</a></h3><p>十幅浮雕由刘开渠、滑田友、萧传玖、曾竹韶等著名雕塑家创作，是中国现代雕塑艺术的杰作。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>纪念碑参观（约30分钟）</strong>：</p><p>绕碑一周 → 细读正面题词 → 阅读背面碑文 → 观赏十幅浮雕 → 拍照留念</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">1号线天安门东站或西站</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">1路、2路、52路等天安门站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从故宫步行约10分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>庄重参观</strong>：怀着崇敬之心参观</li><li><strong>仔细阅读</strong>：建议仔细阅读碑文，了解历史</li><li><strong>观赏浮雕</strong>：浮雕生动，值得细细观赏</li><li><strong>拍照留念</strong>：可拍照，但请保持庄重</li><li><strong>结合游览</strong>：可与天安门广场、故宫一起游览</li></ol><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>人民英雄纪念碑是中国人民革命精神的象征，是中华民族精神的丰碑。</p><p>正如碑文所说：</p><blockquote><p>&quot;人民英雄永垂不朽！&quot;</p></blockquote><p>纪念碑铭记着为民族独立和人民解放而英勇牺牲的革命先烈，激励着后人继承先烈遗志，为实现中华民族伟大复兴而奋斗。</p><hr><p><strong>📍 地址</strong>：北京市东城区天安门广场中央 <strong>🚇 地铁</strong>：1号线天安门东站或西站</p>',50)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
